return ['x-generator'=>'GlotPress/4.0.1','translation-revision-date'=>'2025-05-26 08:25:40+0000','plural-forms'=>'nplurals=3; plural=(n % 10 == 1 && n % 100 != 11) ? 0 : ((n % 10 >= 2 && n % 10 <= 4 && (n % 100 < 12 || n % 100 > 14)) ? 1 : 2);','project-id-version'=>'Plugins - Theme Check - Stable (latest release)','language'=>'ru','messages'=>['Themes Team'=>'Тематическая группа','The tag %s is being used, please remove it from your style.css header. It is only allowed for Block Themes.'=>'Используется метка %s, пожалуйста, удалите её из заголовка style.css. Они разрешены только для блочных тем.','Could not find the index.html template in the theme.'=>'Не удалось найти шаблон index.html в теме.','Could not find the file theme.json in the theme.'=>'Не удалось найти файл theme.json в теме.','%1$s was found in the file %2$s. %3$s.'=>'%1$s найден в файле %2$s. %3$s.','Theme Check is maintained by %s.'=>'Theme Check поддерживается %s.','Running %1$s tests against %2$s.'=>'Выполнение %1$s тестов против %2$s.','<strong>Tested up to</strong> is recommended to have major versions only (e.g. 5.8). Patch version is not needed (e.g. 5.8.1).'=>'<strong>Проверено до</strong> Рекомендуется использовать только основные версии (например, 5.8). Патч-версия не нужна (например, 5.8.1).','<strong>Requires PHP</strong> is recommended to have major and minor versions only (e.g. 7.4). Patch version is not needed (e.g. 7.4.1).'=>'<strong>Требуется PHP</strong> Рекомендуется иметь только основные и дополнительные версии (например, 7.4). Патч-версия не нужна (например, 7.4.1).','<strong>&lt;title&gt;</strong> tag was found in the file %1$s. Document titles must not be hard coded, use <strong>add_theme_support( "title-tag" )</strong> instead'=>'<strong>&lt;title&gt;</strong> тег найден в файле %1$s. Названия документов не должны быть жестко закодированы, используйте <strong>add_theme_support( "title-tag" )</strong> вместо этого','<strong>wp_title()</strong> was found in the file %1$s. wp_title was historically used for the document &lt;title&gt; tag and was never intended for other purposes. Use <strong>add_theme_support( "title-tag" )</strong> instead'=>'<strong>wp_title()</strong> найден в %1$s. wp_title исторически использовался для тега документа &lt;title&gt; и никогда не предназначался для других целей. Используйте <strong>add_theme_support( "title-tag" )</strong> вместо этого','Found a translation function that is missing a text-domain in the file %1$s. Function %2$s, with the arguments %3$s. %4$s'=>'Найдена функция перевода, в которой отсутствует текстовый домен в файле %1$s. Функция %2$s, с аргументами %3$s. %4$s','Found a translation function that has an incorrect number of arguments in the file %1$s. Function %2$s, with the arguments %3$s. %4$s'=>'Найдена функция перевода, которая имеет неправильное количество аргументов в файле %1$s. Функция %2$s, с аргументами %3$s. %4$s','Found a script tag in %s. Scripts and styles need to be enqueued or added via a hook, otherwise it is more difficult to remove or replace them with plugins or child themes.'=>'Найден тег script в %s. Скрипты и стили должны вызываться или добавляться через хук, иначе их будет сложнее удалить или заменить плагинами или дочерними темами.','The theme uses <strong>remove_action %1$s %2$s</strong> in the file %3$s. This is plugin-territory functionality and must not be used in themes. Use a plugin instead. %4$s'=>'Тема использует <strong>remove_action %1$s %2$s</strong> в файле %3$s. Это функциональность плагина, и она не должна использоваться в темах. Вместо этого используйте плагин. %4$s','The theme uses the %1$s %2$s in the file %3$s. This is plugin-territory functionality and must not be used in themes. Use a plugin instead. %4$s'=>'Тема использует %1$s %2$s в файле %3$s. Это функциональность плагина, и она не должна использоваться в темах. Вместо этого используйте плагин. %4$s','The theme uses the %1$s function in the file %2$s. %1$s is plugin-territory functionality and must not be used in themes. Use a plugin instead. %3$s'=>'Тема использует %1$s функцию в файле %2$s. %1$s - функциональность плагина, и она не должна использоваться в темах. Вместо этого используйте плагин. %3$s','%1$s is %2$s in size. Large file sizes have a negative impact on website performance and loading time. Compress images before using them.'=>'%1$s имеет размер %2$s. Большие размеры файлов негативно влияют на производительность сайта и время загрузки. Сжимайте изображения перед их использованием.','Possible variable %1$s found in translation function in %2$s. Translation function calls must not contain PHP variables, use placeholders instead. See <a href="%3$s" target="_blank">Internationalization Guidelines (Opens in a new window)</a>. %4$s'=>'Возможная переменная %1$s найдена в функции перевода в %2$s. Вызовы функций перевода не должны содержать переменные PHP, вместо них используйте заполнители. Смотрите <a href="%3$s" target="_blank">Руководство по интернационализации (Откроется в новом окне)</a>. %4$s','This theme appears to have been auto-generated.'=>'Похоже, что эта тема была сгенерирована автоматически.','Theme Check is not able to determine if WP_Filesystem is used correctly. WP_Filesystem should only be used for theme upgrade operations, not for all file operations. Before continuing, you must manually review the code. Consider using file_get_contents(), scandir(), or glob(). It is not recommended to make changes to third-party frameworks that use WP_Filesystem, for example, TGMPA'=>'Theme Check не может определить, правильно ли используется WP_Filesystem. WP_Filesystem должна использоваться только для операций обновления темы, а не для всех файловых операций. Прежде чем продолжить, вы должны вручную просмотреть код. Рассмотрите возможность использования file_get_contents(), scandir() или glob(). Не рекомендуется вносить изменения в сторонние фреймворки, использующие WP_Filesystem, например, TGMPA','%1$s %2$s found. This file must not be in the production version of the theme.'=>'%1$s %2$s найден. Этот файл не должен находиться в рабочей версии темы.','Learn how to add a copyright notice (opens in a new window).'=>'Узнайте, как добавить уведомление об авторских правах ( откроется в новом окне).','Could not find a copyright notice for the theme. A copyright notice is needed if your theme is licenced as GPL.'=>'Не удалось найти уведомление об авторских правах для темы. Уведомление об авторских правах необходимо, если ваша тема лицензирована как GPL.','Found wp_deregister_script in %1$s. Themes must not deregister scripts that are included in WordPress. Deregistering third party scripts that are registered by parent themes is allowed.'=>'Найден wp_deregister_script в %1$s. Темы не должны отменять регистрацию скриптов, включенных в WordPress. Разрешена отмена регистрации сторонних скриптов, зарегистрированных родительскими темами.','Both DOS and UNIX style line endings were found in the file %s. This causes a problem with SVN repositories and must be corrected before the theme can be accepted. Please change the file to use only one style of line endings.'=>'В файле %s были обнаружены окончания строк в стиле DOS и UNIX. Это вызывает проблемы с SVN-репозиториями и должно быть исправлено до того, как тема будет принята. Пожалуйста, измените файл, чтобы использовать только один стиль окончания строк.','Using a WordPress.org Theme URI is reserved for default and bundled themes (Twenty * series).'=>'Использование URI темы WordPress.org зарезервировано для стандартных и связанных тем (серия Twenty *).','No reference to <strong>add_theme_support( "wp-block-styles" )</strong> was found in the theme. It is recommended that the theme implement this functionality.'=>'В теме не найдено <strong>add_theme_support("wp-block-styles" )</strong>. Рекомендуется, чтобы в теме была реализована эта функциональность.','No reference to <strong>add_theme_support( "align-wide" )</strong> was found in the theme. It is recommended that the theme implement this functionality.'=>'В теме не найдено <strong>add_theme_support("align-wide" )</strong>. Рекомендуется, чтобы в теме была реализована эта функциональность','No reference to <strong>add_theme_support( "responsive-embeds" )</strong> was found in the theme. It is recommended that the theme implement this functionality.'=>'В теме не найдено <strong>add_theme_support("responsive-embeds" )</strong>. Рекомендуется, чтобы в теме была реализована эта функциональность.','No reference to <strong>add_theme_support( "html5", $args )</strong> was found in the theme. It is strongly recommended that the theme implement this functionality.'=>'В теме не найдено <strong>add_theme_support( "html5", $args )</strong>. Настоятельно рекомендуется, чтобы в теме была реализована эта функциональность.','No reference to <strong>add_theme_support( "custom-logo", $args )</strong> was found in the theme. It is recommended that the theme implement this functionality.'=>'В теме не найдено <strong>add_theme_support( "custom-logo", $args )</strong>. Рекомендуется, чтобы в теме была реализована эта функциональность.','<strong>.screen-reader-text</strong> CSS class is generated by WordPress and needs to be styled with your theme CSS. See <a href="http://codex.wordpress.org/CSS#WordPress_Generated_Classes">the Codex</a> for an example implementation.'=>'CSS-класс <strong>.screen-reader-text</strong> создается WordPress и должен быть оформлен с помощью CSS вашей темы. Пример реализации см. в <a href="http://codex.wordpress.org/CSS#WordPress_Generated_Classes">Кодексе</a>.','Use <strong>get_search_form()</strong> instead of hard coding forms. Otherwise, the form can not be filtered.'=>'Используйте <strong>get_search_form()</strong> вместо жесткого кодирования форм. В противном случае форма не сможет быть отфильтрована.','<strong>role="search"</strong> was found in %1$s. %2$s'=>'<strong>role="search"</strong> найдено в %1$s. %2$s','<strong>searchform.php</strong> was found in %1$s. %2$s'=>'<strong>searchform.php</strong> найдено в %1$s. %2$s','Use <strong>get_search_form()</strong> instead of including searchform.php directly. Otherwise, the form can not be filtered.'=>'Используйте <strong>get_search_form()</strong> вместо того, чтобы включать searchform.php напрямую. В противном случае форма не сможет быть отфильтрована.','Found <strong>%1$s</strong> in the file <strong>%2$s</strong>.'=>'Найдено <strong>%1$s</strong> в файле <strong>%2$s</strong>.','Found %1$s in the file %2$s.'=>'Найдено %1$s в %2$s.','HTTP requests should be made using the WordPress HTTP wrappers, such as wp_safe_remote_get() and wp_safe_remote_post()'=>'HTTP-запросы должны выполняться с использованием HTTP-оберток WordPress, таких как wp_safe_remote_get() и wp_safe_remote_post().','File write operations should are avoided unless necessary'=>'Следует избегать операций записи в файл, если в этом нет необходимости.','File read operations should use file_get_contents() but are discouraged unless required'=>'Операции чтения файлов должны использовать функцию file_get_contents(), но не рекомендуется, если это не требуется','No reference to <strong>register_block_style</strong> was found in the theme. Theme authors are encouraged to implement new block styles as a transition to block themes.'=>'В теме не найдено упоминания <strong>register_block_style</strong>. Авторам тем рекомендуется внедрять новые стили блоков в качестве перехода к блочным темам.','No reference to <strong>register_block_pattern</strong> was found in the theme. Theme authors are encouraged to implement custom block patterns as a transition to block themes.'=>'В теме не найдено <strong>register_block_pattern</strong>. Авторам тем рекомендуется внедрять пользовательские блочные паттерны в качестве перехода к блочным темам.','Found a copy of Underscores. Using underscores.me as Theme URI or Author URI is not allowed. Update the files for your own theme.'=>'Найдена копия Underscores. Использование underscores.me в качестве URI темы или URI автора запрещено. Обновите файлы для своей собственной темы.','Make sure to review the guidelines at %1$sTheme Review%2$s before uploading a Theme.'=>'Перед загрузкой темы обязательно ознакомьтесь с рекомендациями на странице %1$sОбзора темы%2$s.','The WordPress Themes Team'=>'Команда тем WordPress','Please test your theme with %1$sdebug enabled%2$s before you upload!'=>'Пожалуйста, протестируйте вашу тему с %1$sвключенной отладкой%2$s перед загрузкой!','WP_DEBUG is not enabled!'=>'WP_DEBUG не активирован!','Potential affiliate link detected'=>'Обнаружена потенциальная партнерская ссылка','Sharesale affiliate link detected'=>'Обнаружена партнерская ссылка Sharesale','function nameThemes should not use <strong>%s()</strong>.'=>'Темы не должны использовать <strong>%s()</strong>.','Developing with WordPress Forum'=>'Разработка с форумом WordPress','Theme Handbook'=>'Руководство по созданию тем','Useful Links'=>'Полезные ссылки','Every call to the <strong>add_setting()</strong> method needs to have a sanitization callback function passed.'=>'Каждый вызов метода <strong>add_setting()</strong> должен содержать переданную коллбэк-функцию санитизации.','Found a Customizer setting called %1$s in %2$s that did not have a sanitization callback function. '=>'Найдена настройка "Кастомайзера" под названием %1$s в %2$s, которая не имеет коллбэк-функцию санитизации.','The theme is using `#wpadminbar` in %1$s. Hiding the admin bar is not allowed. This warning must be manually checked.'=>'Тема использует `#wpadminbar` в %1$s. Скрытие панели администратора не допускается. Это предупреждение необходимо проверить вручную.','%1$s Themes are not allowed to hide the admin bar. This warning must be manually checked.'=>'Темам %1$s не разрешено скрывать панель администратора. Это предупреждение необходимо проверить вручную.','Found %1$s in %2$s. %3$s. A manual review is needed.'=>'Найдено %1$s в %2$s. %3$s. Необходима ручная проверка.','Found %1$s in %2$s. <a href="%3$s" target="_blank">Theme options must be escaped (Opens in a new window).</a>. '=>'Найдено %1$s в %2$s. <a href="%3$s" target="_blank">Опции темы должны быть экранированы (откроется в новом окне).</a>.','get_template_directory_uri() must be escaped when output as part of a link or image source. Use esc_url() for link attributes'=>'get_template_directory_uri() должна быть экранирована при выводе в качестве части ссылки или источника изображения. Используйте esc_url() для атрибутов ссылок','home_url() must be escaped. Use esc_url() for link attributes'=>'home_url() должен быть экранирован. Используйте esc_url() для атрибутов ссылок','Only use esc_attr_e() inside HTML attributes. Use esc_html_e() between HTML tags'=>'Используйте esc_attr_e() только внутри атрибутов HTML. Используйте esc_html_e() между тегами HTML','Only use esc_attr__() inside HTML attributes. Use esc_html__() between HTML tags'=>'Используйте esc_attr__() только внутри атрибутов HTML. Используйте esc_html__() между тегами HTML','Only use esc_attr() inside HTML attributes. Use esc_html() between HTML tags'=>'Используйте esc_attr() только внутри атрибутов HTML. Используйте esc_html() между тегами HTML','Use esc_attr() inside HTML attributes, and esc_url() for link attributes'=>'Используйте esc_attr() внутри атрибутов HTML и esc_url() для атрибутов ссылок','Use esc_attr__() inside HTML attributes, and esc_url() for link attributes'=>'Используйте esc_attr__() внутри атрибутов HTML и esc_url() для атрибутов ссылок','Use esc_attr_e() inside HTML attributes, and esc_url() for link attributes'=>'Используйте esc_attr_e() внутри атрибутов HTML и esc_url() для атрибутов ссылок','View license (opens in a new window).'=>'Посмотреть лицензию (откроется в новом окне)','Found a reference to %s. Assets from this website does not use a license that is compatible with GPL.'=>'Найдена ссылка на %s. Ресурсы с этого веб-сайта не используют лицензию, совместимую с GPL.','A menu name is being used for a menu in %1$s. By using menu name, the menu would be required to have the exact same name in the WordPress admin area. Use a theme_location instead.'=>'Имя меню используется для меню в %1$s. При использовании имени меню, меню должно иметь точно такое же имя в административной области WordPress. Вместо этого используйте theme_location.','A menu without a theme_location was found in %1$s.'=>'Меню без theme_location было найдено в %1$s.','A menu without a theme_location was found in %1$s. %2$s is used inside wp_nav_menu(). You must manually check if the theme_location is included.'=>'Меню без theme_location было найдено в %1$s. %2$s используется внутри wp_nav_menu(). Вы должны вручную проверить, включен ли theme_location.','Found a copy of Underscores. See %1$s. Update the files for your own theme.'=>'Найдена копия Underscores. См. %1$s. Обновите файлы для своей темы.','Found a copy of Underscores. See %1$s. <a href="https://github.com/Automattic/_s" target="_new">Learn how to update the files for your own theme.</a>'=>'Найдена копия Underscores. См. %1$s. <a href="https://github.com/Automattic/_s" target="_new">Узнайте, как обновить файлы для вашей собственной темы.</a>','<strong>Requires PHP:</strong> is missing from your style.css header.'=>'<strong>Requires PHP:</strong> отсутствует в вашем заголовке style.css.','<strong>Tested up to:</strong> is missing from your style.css header. Also, this should be numbers only, so <em>5.0</em> and not <em>WP 5.0</em>'=>'<strong>Tested up to:</strong> отсутствует в вашем заголовке style.css. Кроме того, это должны быть только числа, поэтому <em>5.0</em>, а не <em>WP 5.0</em>','Favicon'=>'Фавикон','Shell script file'=>'Файл сценария оболочки','XML file'=>'XML-файл','Customizer import file'=>'Файл импорта настроек','Widget import file'=>'Файл импорта виджетов','wp_body_open action or function call at the very top of the body just after the opening body tag'=>'Вызов действия или функции wp_body_open в самой верхней части body сразу после открывающего тега body','See: <a href="https://developer.wordpress.org/reference/functions/wp_body_open/">wp_body_open</a><pre> &lt;?php wp_body_open(); ?&gt;</pre>'=>'См.: <a href="https://developer.wordpress.org/reference/functions/wp_body_open/">wp_body_open</a><pre> &lt;?php wp_body_open(); ?&gt;</pre>','site_url() or get_site_url() was found in %s. site_url() references the URL where the WordPress files are located. Use home_url() if the intention is to point to the site address (home page), and in the search form.'=>'site_url() или get_site_url() найдено в %s. site_url() ссылается на URL, где расположены файлы WordPress. Используйте home_url(), если вы хотите сослаться на адрес сайта (домашнюю страницу), а также в форме поиска.','https://github.com/WordPress/theme-check/'=>'https://github.com/WordPress/theme-check/','See Theme Tags'=>'См. теги темы','A maximum of 3 subject tags are allowed. The theme has %1$u subjects tags ( %2$s ). Please remove the subject tags, which do not directly apply to the theme.'=>'Допускается не более 3 тематических тегов. Тема имеет %1$u тематических тегов ( %2$s ). Пожалуйста, удалите теги темы, которые не относятся непосредственно к теме.','The tag %s is being used more than once, please remove it from your style.css header.'=>'Тег %s используется более одного раза, пожалуйста, удалите его из заголовка style.css.','Reference to %1$s was found in the theme. This should be removed and %2$s used instead.'=>'В теме найдена ссылка на %1$s. Это следует удалить и использовать вместо него %2$s.','No reference to <strong>add_theme_support( "title-tag" )</strong> was found in the theme.'=>'Ссылка на <strong>add_theme_support( "title-tag" )</strong> не найдена в теме.','This theme\'s correct slug and text-domain is %s.'=>'Правильный ярлык и текстовый домен этой темы - %s.','This theme text domain does not match the theme\'s slug. The text domain used: %s'=>'Этот текстовый домен темы не соответствует ярлыку темы. Используемый текстовый домен: %s','The tag %s has been deprecated, please remove it from your style.css header.'=>'Тег %s устарел, пожалуйста, удалите его из заголовка style.css.','See <a href="https://make.wordpress.org/themes/handbook/review/accessibility/">https://make.wordpress.org/themes/handbook/review/accessibility/</a>'=>'См. <a href="https://make.wordpress.org/themes/handbook/review/accessibility/">https://make.wordpress.org/themes/handbook/review/accessibility/</a>','Themes that use the tag accessibility-ready will need to undergo an accessibility review.'=>'Темы, которые используют тег accessibility-ready, должны пройти проверку доступности.','<strong>Zip file found.</strong> Plugins are not allowed in themes. The zip file found was <em>%s</em>.'=>'<strong>Найден Zip файл.</strong> Плагины не допускаются в темах.
Обнаруженный zip файл <em>%s</em>.','Zipped Plugin'=>'Упакованый ZIP плагин','Lubith theme generator file'=>'Файл генератора тем Lubith','Possible Favicon found in %1$s. Favicons are handled by the Site Icon setting in the customizer since version 4.3.'=>'Возможный значок favicon найден в %1$s. Значки favicon управляются интерфейсом настройки темы начиная с версии 4.3.','This child theme requires at least version %1$s of theme %2$s to be installed. You only have %3$s please update the parent theme.'=>'Эта дочерняя тема требует, по крайней мере, версии %1$s темы %2$s для установки. У вас есть только %3$s пожалуйста, обновите родительскую тему.','At least one hard coded date was found in the file %1$s. Consider %2$s instead.'=>'В файле %1$s была найдена по крайней мере одна жестко закодированная дата. Вместо этого рассмотрим %2$s .','The domain found is %s.'=>'Найден домен: %s.','The domains found are %s.'=>'Найдены домены: %s','(If this is a child theme, you can ignore this error.)'=>'(Если это дочерняя тема, вы можете игнорировать эту ошибку.)','Found wrong tag, remove %s from your style.css header.'=>'Найден неправильный тег, удалите %s из заголовка style.css.','%s is missing from your style.css header.'=>'%s отсутствует в заглавии style.css.','%1$s was found in the file %2$s. However get_post_format and/or has_post_format were not found, and no use of formats in the CSS was detected.'=>'%1$s был найден в файле %2$s. Однако get_post_format и/или has_post_format не были найдены, и не было обнаружено использования форматов в CSS.','Found PHP short tags in file %s.'=>'PHP short tag найдены в файле %s.','Possible hard-coded links were found in the file %s.'=>'Возможные жестко закодированные ссылки были найдены в файле %s.','%1$s was found in the file %2$s %3$s.'=>'В файле %1$s было найдено %2$s %3$s.','Could not find the file %s in the theme.'=>'Не могу найти файл %s в теме.','%1$s was found in the file %2$s. Use %3$s instead.'=>'В файле %1$s был найден файл %2$s. Используйте вместо него файл %3$s.','Could not find %1$s. %2$s'=>'Невозможно найти %1$s. %2$s','title of the main pageTheme Check'=>'Проверка темы','The code for Theme Check can be contributed to on <a href="%s">GitHub</a>.'=>'Можете поучаствовать в разработке кода Theme Check на <a href="%s">GitHub</a>.','Only one text-domain is being used in this theme. Make sure it matches the theme\'s slug correctly so that the theme will be compatible with WordPress.org language packs.'=>'В этой теме используется только один текстовый домен. Убедитесь, что он соответствует ярлыку темы, чтобы тема была совместима с языковыми пакетами WordPress.org.','More than one text-domain is being used in this theme. This means the theme will not be compatible with WordPress.org language packs.'=>'Более чем один текстовый домен был использован в теме. Это означает, что тема не будет совместима с языковыми пакетами WordPress.org.','Your theme appears to be in the wrong directory for the theme name. The directory name must match the slug of the theme. This theme\'s correct slug and text-domain is %s.'=>'Ваша тема находится в директории не соответствующей названию темы. Имя директории должно соответствовать ярлыку темы. Ярлык и текстовый домен этой темы %s.','A simple and easy way to test your theme for all the latest WordPress standards and practices. A great theme development tool!'=>'Простой и легкий способ протестировать вашу тему в соответствии с последними стандартами WordPress. Отличный инструмент в разработке тем!','Theme Check'=>'Theme Check','You do not have sufficient permissions to access this page.'=>'У вас недостаточно полномочий для доступа к этой странице.','Suppress INFO.'=>'Отладочная информация.','Output in Trac format.'=>'Вывод в формате Trac.','Check it!'=>'Проверить!','Theme Unit Tests'=>'Модульное тестирование темы','Now that your theme has passed the basic tests you need to check it properly using the test data before you upload it to the WordPress Themes Directory.'=>'Теперь, когда ваша тема прошла основные тесты, вам нужно проверить её правильность с помощью тестовых данных, прежде чем загружать её в каталог тем WordPress.','Contact'=>'Контактная информация','The Theme Check plugin is an easy way to test your theme and make sure it\'s up to date with the latest theme review standards. With it, you can run all the same automated testing tools on your theme that WordPress.org uses for theme submissions.'=>'Плагин проверки тем - это простой и легкий способ протестировать вашу тему и убедиться, что она соответствует последним стандартам проверки тем. С ним вы можете запускать все те автоматические инструменты тестирования в вашей теме, которые использует WordPress.org для валидации тем.','About'=>'О плагине','%1$s passed the tests'=>'Тема %1$s прошла тестирование','One or more errors were found for %1$s.'=>'Одна или более ошибок были найдены для %1$s.','Child theme is only tested up to version %1$s of %2$s breakage may occur! %3$s installed version is %4$s'=>'Дочерняя тема тестировалась только включая версию %1$s %2$s и может содержать ошибки!  Установлена версия %3$s %4$s','Child theme does not have the <strong>Template Version</strong> tag in style.css.'=>'Дочерняя тема не содержит метки <strong>Template Version</strong> в style.css','This is a child theme. The parent theme is: %s. These files have been included automatically!'=>'Это дочерняя тема. Родительская темы - %s. Эти файлы будут включены в проверку автоматически!','Description'=>'Описание','Tags'=>'Метки','License URI'=>'Ссылка на лицензию','License'=>'Лицензия','Theme URI'=>'Ссылка на тему','Author URI'=>'Ссылка на автора','Author'=>'Автор','Version'=>'Версия','Title'=>'Название','Theme Info'=>'О Теме','Symptom of the "Pharma Hack" <a href="http://blog.sucuri.net/2010/07/understanding-and-cleaning-the-pharma-hack-on-wordpress.html">[1]</a>'=>'Обнаружены подозрения на вирус "Pharma Hack" <a href="http://blog.sucuri.net/2010/07/understanding-and-cleaning-the-pharma-hack-on-wordpress.html">[1]</a>','Tells a hacker what operating system your server is running'=>'Сообщает хакеру операционную систему вашего сервера','This may be a script used by hackers to get control of your server'=>'Это может быть скрипт, используемый хакерами для контролирования вашего сервера','This may be a script used by hackers to get control of your server!'=>'Это может быть скрипт, используемый хакерами для контролирования вашего сервера!','Sidebars need to be registered in a custom function hooked to the <strong>widgets_init</strong> action. See: %s.'=>'Панели виджетов должны быть зарегистрированы в пользовательской функции, содержащей хук <strong>widgets_init</strong>. Смотрите %s.','The theme appears to use <strong>register_sidebar()</strong> but no <strong>dynamic_sidebar()</strong> was found. See: <a href=\'https://developer.wordpress.org/reference/functions/dynamic_sidebar/\'>dynamic_sidebar</a><pre> &lt;?php dynamic_sidebar( $index ); ?&gt;</pre>'=>'Тема, по-видимому, использует <strong>register_sidebar()</strong>, но не было найдено <strong>dynamic_sidebar()</strong>. См.: <a href=\'https://developer.wordpress.org/reference/functions/dynamic_sidebar/\'>dynamic_sidebar</a><pre> &lt;?php dynamic_sidebar( $index ); ?&gt;</pre>','This theme contains no sidebars/widget areas. See <a href=\'https://codex.wordpress.org/Widgets_API\'>Widgets API</a>'=>'Эта тема не содержит ни одной панели виджетов. Смотрите <a href=\'https://codex.wordpress.org/Widgets_API\'>Widgets API</a>','This theme doesn\'t seem to display tags. Modify it to display tags in appropriate locations.'=>'Кажется, эта тема не отображает тэги. Тэги должны отображаться в соответствующих местах, исправьте это.','<strong>Tags:</strong> is either empty or missing in style.css header.'=>'<strong>Тэги:</strong> не содержат символов или пропущены в шапке вашего style.css.','<strong>Text Domain:</strong> is missing from your style.css header.'=>'<strong>Text Domain:</strong> пропущен в заголовке вашего style.css.','<strong>.gallery-caption</strong> css class is recommended in your theme css.'=>'Рекомендуется использовать класс <strong>.gallery-caption</strong> в css вашей темы.','<strong>.wp-caption-text</strong> css class is recommended in your theme css.'=>'Рекомендуется использовать класс <strong>.wp-caption-text</strong> в css вашей темы.','<strong>.wp-caption</strong> css class is recommended in your theme css.'=>'Рекомендуется использовать класс <strong>.wp-caption</strong> в css вашей темы.','<strong>.aligncenter</strong> css class is recommended in your theme css.'=>'Рекомендуется использовать <strong>.aligncenter</strong> css-класс в css вашей темы.','<strong>.alignright</strong> css class is recommended in your theme css.'=>'Рекомендуется использовать <strong>.alignright</strong> css-класс в css вашей темы.','<strong>.alignleft</strong> css class is recommended in your theme css.'=>'Рекомендуется использовать <strong>.alignleft</strong> css-класс в css вашей темы.','<strong>.bypostauthor</strong> css class is recommended in your theme css.'=>'Рекомендуется использовать класс <strong>.bypostauthor</strong> в css вашей темы.','<strong>.sticky</strong> css class is recommended in your theme css.'=>'Рекомендуется использовать класс <strong>.sticky</strong> в css вашей темы.','<strong>License URI:</strong> is missing from your style.css header.'=>'<strong>License URI:</strong> пропущен в шапке вашего style.css.','<strong>License:</strong> is missing from your style.css header.'=>'<strong>License:</strong> пропущен в шапке вашего style.css.','<strong>Version:</strong> is missing from your style.css header.'=>'<strong>Version:</strong> пропущен в шапке вашего style.css.','<strong>Author:</strong> is missing from your style.css header.'=>'<strong>Author:</strong> пропущен в шапке вашего style.css.','<strong>Description:</strong> is missing from your style.css header.'=>'<strong>Description:</strong> пропущен в шапке вашего style.css.','<strong>Theme name:</strong> is missing from your style.css header.'=>'<strong>Theme name:</strong> пропущен в шапке вашего style.css.','No screenshot detected! Please include a screenshot.png or screenshot.jpg.'=>'Не обнаружено скриншота! Пожалуйста, загрузите screenshot.png или screenshot.jpg.','Screenshot size should be 1200x900, to account for HiDPI displays. Any 4:3 image size is acceptable, but 1200x900 is preferred.'=>'Размер скриншота должен быть 1200x900, для аккаунтов с HiDPI дисплеями. Все 4:3 изображения приемлимы, но предпочтительнее 1200x900.','Screenshot dimensions are wrong! Ratio of width to height should be 4:3.'=>'Некорректные размеры скриншота! Соотношение ширины и высоты должно быть 4:3','Screenshot is wrong size! Detected: %s. Maximum allowed size is 1200x900px.'=>'Скриншот неправильного размера! Обнаружено: %s. Максимально допустимый размер - 1200x900px.','No reference to <strong>the_post_thumbnail()</strong> was found in the theme. It is recommended that the theme implement this functionality instead of using custom fields for thumbnails.'=>'В этой теме не найдено вызова <strong>the_post_thumbnail()</strong>. Рекомендуется вставить это в тему, чем использовать произвольные поля (custom fields) для вывода миниатюр.','The theme doesn\'t have post pagination code in it. Use <strong>posts_nav_link()</strong> or <strong>paginate_links()</strong> or <strong>the_posts_pagination()</strong> or <strong>the_posts_navigation()</strong> or <strong>next_posts_link()</strong> and <strong>previous_posts_link()</strong> to add post pagination.'=>'Тема не содержит кода постраничной навигации записей. Используйте <strong>posts_nav_link()</strong> или <strong>paginate_links()</strong> или <strong>the_posts_pagination()</strong> или <strong>the_posts_navigation()</strong> или <strong>next_posts_link()</strong> и <strong>previous_posts_link()</strong> для добавления постраничной навигации записей.','Non-printable characters were found in the %s file. You may want to check this file for errors.'=>'В файле %s обнаружены нетипичные символы. Возможно, вы захотите проверить этот файл на наличие ошибок.','No reference to nav_menu\'s was found in the theme. Note that if your theme has a menu bar, it is required to use the WordPress nav_menu functionality for it.'=>'Не было найдено вызовов к меню. Заметьте, если у вашей темы есть панель меню, в ней требуется WordPress функционал nav_menu.','Both DOS and UNIX style line endings were found in the file %1$s. This causes a problem with SVN repositories and must be corrected before the theme can be accepted. Please change the file to use only one style of line endings.'=>'И DOS, и UNIX переводы конца строк были найдены в файле %1$s. Это вызывает проблему с репозиториями SVN и должно быть исправлено перед тем, как тема будет одобрена. Пожалуйста, исправьте это так, чтобы использовался только один вариант завершения строки.','The theme appears to use include or require. If these are being used to include separate sections of a template from independent files, then <strong>get_template_part()</strong> should be used instead.'=>'Для темы применяется использование include или require. Если они были использованы чтобы получать некоторые функции из других файлов, то вместо этого должна использоваться функция <strong>get_template_part()</strong>.','iframes are sometimes used to load unwanted adverts and code on your site'=>'iframe иногда могут подгружать неконтролируемые объявления и выполнять код на вашем сайте.','This theme doesn\'t seem to support the standard avatar functions. Use <strong>get_avatar</strong> or <strong>wp_list_comments</strong> to add this support.'=>'Кажется, эта тема не поддерживает стандартные функции аватара. Используйте <strong>get_avatar</strong> или <strong>wp_list_comments</strong>, чтобы добавить эту поддержку.','OSX system file'=>'Системный файл OSX','SQL dump file'=>'Дамп файл SQL','Server settings file'=>'Файл настроек сервера','PHP error log'=>'Лог ошибок PHP','Dreamweaver project file'=>'Файл проекта Dreamweaver','PHP server settings file'=>'Файл настроек PHP сервера','Hidden Files or Folders'=>'Скрытые файлы или папки','Komodo Project File'=>'Файл проекта Komodo','NetBeans Project File'=>'Файл проекта NetBeans','windows system file'=>'системный файл Windows','Windows thumbnail store'=>'Набор миниатюр Windows','No reference to <strong>add_editor_style()</strong> was found in the theme. It is recommended that the theme implement editor styling, so as to make the editor content match the resulting post output in the theme, for a better user experience.'=>'В теме не найдено вызова к функции <strong>add_editor_style()</strong>. Рекомендуется добавить это в тему, чтобы сделать контент в редакторе выводимым напрямую в тему, а также для улучшения функциональности.','Please remove any extraneous directories like .git or .svn from the ZIP file before uploading it.'=>'Пожалуйста, удалите любые посторонние папки, например .git или .svn из ZIP файла перед его загрузкой.','Use %s instead.'=>'Лучше используйте %s.','%1$s found in the file %2$s. Deprecated since version %3$s.'=>'%1$s найдена в файле %2$s. Устарела с версии %3$s.','No reference to <strong>add_theme_support( "custom-background", $args )</strong> was found in the theme. If the theme uses background images or solid colors for the background, then it is recommended that the theme implement this functionality.'=>'В теме не найдено вызова к функции  <strong>add_theme_support( "custom-background", $args )</strong>. Если тема использует изображения фона или выраженные цвета для фона, то рекомендуется использовать этот функционал.','No reference to <strong>add_theme_support( "custom-header", $args )</strong> was found in the theme. It is recommended that the theme implement this functionality if using an image for the header.'=>'В теме не найдено вызова к функции <strong>add_theme_support( "custom-header", $args )</strong>. Рекомендуется добавить этот функционал, если вы хотите использовать изображение в шапке сайта.','Found a Customizer setting called %1$s in %2$s that had an empty value passed as sanitization callback. You need to pass a function name as sanitization callback.'=>'Найден параметр "Кастомайзера" под названием %1$s в %2$s, которому было передано пустое значение в коллбэк-функции санитизации . Вам необходимо передать имя функции в качестве обратного вызова санитизации.','The theme doesn\'t have comment pagination code in it. Use <strong>paginate_comments_links()</strong> or <strong>the_comments_navigation</strong> or <strong>the_comments_pagination</strong> or <strong>next_comments_link()</strong> and <strong>previous_comments_link()</strong> to add comment pagination.'=>'Тема не содержит кода постраничной навигации по комментариям. Используйте <strong>paginate_comments_links()</strong> или <strong>the_comments_navigation</strong> или <strong>the_comments_pagination</strong> или <strong>next_comments_link()</strong> и <strong>previous_comments_link()</strong> для добавления постраничной навигации комментариев.','Could not find the <strong>comment-reply</strong> script enqueued, however a reference to \'comment-reply\' was found. Make sure that the comment-reply script is being enqueued properly on singular pages.'=>'Невозможно найти скрипт <strong>comment-reply</strong>, однако вызов вывода \'comment-reply\' был найден. Убедитесь, что скрипт comment-reply был вставлен именно на страницы одиночных записей.','INFO'=>'ИНФОРМАЦИЯ','Could not find the <strong>comment-reply</strong> script enqueued.'=>'Не удалось найти сценарий <strong>comment-reply</strong>, находящийся в очереди.','Found the URL of a CDN in the code: %s. You should not load CSS or Javascript resources from a CDN, please bundle them with the theme.'=>'Найдена ссылка на CDN в коде: %s. Вы не должны подгружать CSS или Javascript ресурсы с CDN, пожалуйста, включите их в тему.','RECOMMENDED'=>'РЕКОМЕНДУЕТСЯ','body_class call in body tag'=>'Вызов body_class в тэге body','add_theme_support( \'automatic-feed-links\' )'=>'add_theme_support( \'automatic-feed-links\' )','See: <a href="https://developer.wordpress.org/reference/functions/post_class/">post_class</a><pre> &lt;div id="post-&lt;?php the_ID(); ?&gt;" &lt;?php post_class(); ?&gt;&gt;</pre>'=>'См.: <a href="https://developer.wordpress.org/reference/functions/post_class/">post_class</a><pre> &lt;div id="post-&lt;?php the_ID(); ?&gt;" &lt;?php post_class(); ?&gt;&gt;</pre>','See: <a href="https://developer.wordpress.org/reference/functions/wp_link_pages/">wp_link_pages</a><pre> &lt;?php wp_link_pages( $args ); ?&gt;</pre>'=>'См.: <a href="https://developer.wordpress.org/reference/functions/wp_link_pages/">wp_link_pages</a><pre> &lt;?php wp_link_pages( $args ); ?&gt;</pre>','See: <a href="https://developer.wordpress.org/reference/functions/body_class/">body_class</a><pre> &lt;?php body_class( $class ); ?&gt;</pre>'=>'См.: <a href="https://developer.wordpress.org/reference/functions/body_class/">body_class</a><pre> &lt;?php body_class( $class ); ?&gt;</pre>','See: <a href="https://developer.wordpress.org/reference/functions/comment_form/">comment_form</a><pre> &lt;?php comment_form(); ?&gt;</pre>'=>'См.: <a href="https://developer.wordpress.org/reference/functions/comment_form/">comment_form</a><pre> &lt;?php comment_form(); ?&gt;</pre>','See: <a href="https://developer.wordpress.org/reference/functions/wp_list_comments/">wp_list_comments</a><pre> &lt;?php wp_list_comments( $args ); ?&gt;</pre>'=>'См.: <a href="https://developer.wordpress.org/reference/functions/wp_list_comments/">wp_list_comments</a><pre> &lt;?php wp_list_comments( $args ); ?&gt;</pre>','See: <a href="https://developer.wordpress.org/reference/functions/comments_template/">comments_template</a><pre> &lt;?php comments_template( $file, $separate_comments ); ?&gt;</pre>'=>'См.: <a href="https://developer.wordpress.org/reference/functions/comments_template/">comments_template</a><pre> &lt;?php comments_template( $file, $separate_comments ); ?&gt;</pre>','See: <a href="https://developer.wordpress.org/reference/functions/add_theme_support/">add_theme_support</a><pre> &lt;?php add_theme_support( $feature ); ?&gt;</pre>'=>'См.: <a href="https://developer.wordpress.org/reference/functions/add_theme_support/">add_theme_support</a><pre> &lt;?php add_theme_support( $feature ); ?&gt;</pre>','There must be a charset defined in the Content-Type or the meta charset tag in the head.'=>'Должен быть набор символов, определенный в Content-Type или meta тэге в head.','See: <a href="https://developer.wordpress.org/reference/functions/language_attributes/">language_attributes</a><pre>&lt;html &lt;?php language_attributes(); ?&gt;</pre>'=>'См.: <a href="https://developer.wordpress.org/reference/functions/language_attributes/">language_attributes</a><pre>&lt;html &lt;?php language_attributes(); ?&gt;</pre>','See: <a href="https://developer.wordpress.org/reference/functions/wp_head/">wp_head</a><pre> &lt;?php wp_head(); ?&gt;</pre>'=>'См.: <a href="https://developer.wordpress.org/reference/functions/wp_head/">wp_head</a><pre> &lt;?php wp_head(); ?&gt;</pre>','See: <a href="https://developer.wordpress.org/reference/functions/wp_footer/">wp_footer</a><pre> &lt;?php wp_footer(); ?&gt;</pre>'=>'См.: <a href="https://developer.wordpress.org/reference/functions/wp_footer/">wp_footer</a><pre> &lt;?php wp_footer(); ?&gt;</pre>','See: <a href="https://codex.wordpress.org/HTML_to_XHTML">https://codex.wordpress.org/HTML_to_XHTML</a><pre>&lt;!DOCTYPE html PUBLIC "-//W3C//DTD XHTML 1.0 Strict//EN"<br />"http://www.w3.org/TR/xhtml1/DTD/xhtml1-strict.dtd"?&gt;</pre>'=>'Смотрите <a href="https://codex.wordpress.org/HTML_to_XHTML">https://codex.wordpress.org/HTML_to_XHTML</a><pre>&lt;!DOCTYPE html PUBLIC "-//W3C//DTD XHTML 1.0 Strict//EN"<br />"http://www.w3.org/TR/xhtml1/DTD/xhtml1-strict.dtd"?&gt;</pre>','Google advertising code detected'=>'Обнаружен код вывода рекламы Google','Google search code detected'=>'Обнаружен код Google поиска','str_rot13() is not allowed'=>'str_rot13() запрещен','uudecode() is not allowed'=>'uudecode() запрещен','base64_encode() is not allowed'=>'base64_encode() запрещен','base64_decode() is not allowed'=>'base64_decode() запрещен','Themes should not change server PHP settings'=>'Темы не должны менять настройки сервера PHP','PHP system calls are often disabled by server admins and should not be in themes'=>'Системные вызовы PHP часто отключаются администраторами серверов и не должны быть в темах.','eval() is not allowed.'=>'eval() запрещен.','REQUIRED'=>'ТРЕБУЕТСЯ','WARNING'=>'ВНИМАНИЕ!','User levels were deprecated in <strong>2.0</strong>. Please see <a href="https://wordpress.org/support/article/roles-and-capabilities/">Roles and Capabilities</a>'=>'Уровни пользователей были упразднены в версии <strong>2.0</strong>. Посмотрите, пожалуйста, <a href="https://wordpress.org/support/article/roles-and-capabilities/">Роли и возможности</a>','Line '=>'Строка']];